func ThemePreview() templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_ThemePreview_b666`,
		Function: `function __templ_ThemePreview_b666(){function openThemePreview(button) {
		const form = button.closest("form");
		if (!form) return;
		const theme = {};
		form.querySelectorAll("[name^='color_']").forEach((input) => {
			if (input.value) {
				theme[input.name.replace("color_", "")] = input.value;
			}
		});
		const encodedTheme = btoa(JSON.stringify(theme))
			.replace(/\+/g, "-")
			.replace(/\//g, "_")
			.replace(/=+$/, "");
		window.open(globalThis._G.URL_PREFIX + "/preview?t=" + encodedTheme, "_blank", "noopener,noreferrer");
	}
	window.openThemePreview = openThemePreview;
}`,
		Call:       templ.SafeScript(`__templ_ThemePreview_b666`),
		CallInline: templ.SafeScriptInline(`__templ_ThemePreview_b666`),
	}
}

